// --- Secure Token Storage ---

package com.example.sociallogin.storage

import android.content.Context
import androidx.security.crypto.EncryptedSharedPreferences
import androidx.security.crypto.MasterKey

class SecureTokenStorage(context: Context) {

    private val masterKey = MasterKey.Builder(context)
        .setKeyScheme(MasterKey.KeyScheme.AES256_GCM)
        .build()

    private val prefs = EncryptedSharedPreferences.create(
        context,
        "secure_social_login_prefs",
        masterKey,
        EncryptedSharedPreferences.PrefKeyEncryptionScheme.AES256_SIV,
        EncryptedSharedPreferences.PrefValueEncryptionScheme.AES256_GCM
    )

    fun saveAccessToken(provider: String, token: String) {
        prefs.edit().putString("${provider}_access_token", token).apply()
    }

    fun getAccessToken(provider: String): String? {
        return prefs.getString("${provider}_access_token", null)
    }

    fun saveRefreshToken(provider: String, token: String) {
        prefs.edit().putString("${provider}_refresh_token", token).apply()
    }

    fun getRefreshToken(provider: String): String? {
        return prefs.getString("${provider}_refresh_token", null)
    }

    fun clearTokens(provider: String) {
        prefs.edit()
            .remove("${provider}_access_token")
            .remove("${provider}_refresh_token")
            .apply()
    }

    fun clearAll() {
        prefs.edit().clear().apply()
    }
}


