package com.example.sociallogin.network

import com.google.gson.annotations.SerializedName
import retrofit2.Response
import retrofit2.http.Body
import retrofit2.http.POST

data class SocialAuthRequest(
    @SerializedName("provider") val provider: String,
    @SerializedName("auth_code") val authCode: String? = null,
    @SerializedName("access_token") val accessToken: String? = null,
    @SerializedName("id_token") val idToken: String? = null
)

data class AuthResponse(
    @SerializedName("access_token") val accessToken: String,
    @SerializedName("refresh_token") val refreshToken: String,
    @SerializedName("user") val user: UserInfo,
    @SerializedName("expires_in") val expiresIn: Long
)

data class UserInfo(
    @SerializedName("id") val id: String,
    @SerializedName("email") val email: String?,
    @SerializedName("name") val name: String?,
    @SerializedName("profile_picture_url") val profilePictureUrl: String?,
    @SerializedName("provider") val provider: String
)

data class RefreshRequest(
    @SerializedName("refresh_token") val refreshToken: String
)

interface AuthApiService {
    /**
     * Send the OAuth code/token to your backend.
     * The backend holds the client secrets and exchanges
     * the code for tokens server-side.
     */
    @POST("/auth/social")
    suspend fun authenticateWithSocial(
        @Body request: SocialAuthRequest
    ): Response<AuthResponse>

    @POST("/auth/refresh")
    suspend fun refreshToken(
        @Body request: RefreshRequest
    ): Response<AuthResponse>

    @POST("/auth/logout")
    suspend fun logout(): Response<Unit>
}


// --- Network Module ---

package com.example.sociallogin.network

import com.example.sociallogin.config.SocialLoginConfig
import com.example.sociallogin.storage.SecureTokenStorage
import okhttp3.Interceptor
import okhttp3.OkHttpClient
import okhttp3.logging.HttpLoggingInterceptor
import retrofit2.Retrofit
import retrofit2.converter.gson.GsonConverterFactory
import java.security.cert.X509Certificate
import java.util.concurrent.TimeUnit
import javax.net.ssl.SSLContext

object NetworkModule {

    fun createApiService(tokenStorage: SecureTokenStorage): AuthApiService {
        val authInterceptor = Interceptor { chain ->
            val requestBuilder = chain.request().newBuilder()
            tokenStorage.getAccessToken("app")?.let { token ->
                requestBuilder.addHeader("Authorization", "Bearer $token")
            }
            chain.proceed(requestBuilder.build())
        }

        val loggingInterceptor = HttpLoggingInterceptor().apply {
            // Use NONE in production
            level = HttpLoggingInterceptor.Level.NONE
        }

        val client = OkHttpClient.Builder()
            .addInterceptor(authInterceptor)
            .addInterceptor(loggingInterceptor)
            .connectTimeout(30, TimeUnit.SECONDS)
            .readTimeout(30, TimeUnit.SECONDS)
            // Certificate pinning for your backend
            .certificatePinner(
                okhttp3.CertificatePinner.Builder()
                    .add(
                        "your-api-server.example.com",
                        "sha256/AAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAA=" // Replace with your cert pin
                    )
                    .build()
            )
            .build()

        return Retrofit.Builder()
            .baseUrl(SocialLoginConfig.BACKEND_BASE_URL)
            .client(client)
            .addConverterFactory(GsonConverterFactory.create())
            .build()
            .create(AuthApiService::class.java)
    }
}


