// --- Facebook Login Handler ---

package com.example.sociallogin.handlers

import android.app.Activity
import android.content.Intent
import com.example.sociallogin.model.SocialLoginResult
import com.example.sociallogin.network.AuthApiService
import com.example.sociallogin.network.SocialAuthRequest
import com.example.sociallogin.storage.SecureTokenStorage
import com.facebook.CallbackManager
import com.facebook.FacebookCallback
import com.facebook.FacebookException
import com.facebook.login.LoginManager
import com.facebook.login.LoginResult
import kotlinx.coroutines.suspendCancellableCoroutine
import kotlin.coroutines.resume

class FacebookLoginHandler(
    private val apiService: AuthApiService,
    private val tokenStorage: SecureTokenStorage
) {
    private val callbackManager = CallbackManager.Factory.create()

    /**
     * Initiates Facebook login. The Facebook SDK returns an access token
     * which we send to our backend. The backend verifies it with Facebook
     * using the App Secret (which only the backend knows).
     */
    suspend fun login(activity: Activity): SocialLoginResult {
        val fbResult = getFacebookToken(activity)

        return when (fbResult) {
            is FacebookTokenResult.Success -> {
                exchangeTokenWithBackend(fbResult.accessToken)
            }
            is FacebookTokenResult.Error -> {
                SocialLoginResult.Error(fbResult.message, fbResult.exception)
            }
            FacebookTokenResult.Cancelled -> {
                SocialLoginResult.Cancelled
            }
        }
    }

    private suspend fun getFacebookToken(activity: Activity): FacebookTokenResult =
        suspendCancellableCoroutine { continuation ->
            LoginManager.getInstance().registerCallback(
                callbackManager,
                object : FacebookCallback<LoginResult> {
                    override fun onSuccess(result: LoginResult) {
                        continuation.resume(
                            FacebookTokenResult.Success(result.accessToken.token)
                        )
                    }

                    override fun onCancel() {
                        continuation.resume(FacebookTokenResult.Cancelled)
                    }

                    override fun onError(error: FacebookException) {
                        continuation.resume(
                            FacebookTokenResult.Error(
                                error.message ?: "Facebook login failed",
                                error
                            )
                        )
                    }
                }
            )

            LoginManager.getInstance().logInWithReadPermissions(
                activity,
                listOf("email", "public_profile")
            )
        }

    private suspend fun exchangeTokenWithBackend(fbAccessToken: String): SocialLoginResult {
        return try {
            // Send the Facebook access token to our backend.
            // The backend will verify it with Facebook using the App Secret
            // and create/find the user account.
            val response = apiService.authenticateWithSocial(
                SocialAuthRequest(
                    provider = "facebook",
                    accessToken = fbAccessToken
                )
            )

            if (response.isSuccessful && response.body() != null) {
                val authResponse = response.body()!!
                tokenStorage.saveAccessToken("app", authResponse.accessToken)
                tokenStorage.saveRefreshToken("app", authResponse.refreshToken)

                SocialLoginResult.Success(
                    accessToken = authResponse.accessToken,
                    refreshToken = authResponse.refreshToken,
                    user = authResponse.user
                )
            } else {
                SocialLoginResult.Error(
                    "Backend authentication failed: ${response.code()}"
                )
            }
        } catch (e: Exception) {
            SocialLoginResult.Error("Network error: ${e.message}", e)
        }
    }

    fun handleActivityResult(requestCode: Int, resultCode: Int, data: Intent?) {
        callbackManager.onActivityResult(requestCode, resultCode, data)
    }

    fun logout() {
        LoginManager.getInstance().logOut()
        tokenStorage.clearTokens("app")
    }

    private sealed class FacebookTokenResult {
        data class Success(val accessToken: String) : FacebookTokenResult()
        data class Error(val message: String, val exception: Throwable? = null) : FacebookTokenResult()
        object Cancelled : FacebookTokenResult()
    }
}


// --- Google Login Handler ---

package com.example.sociallogin.handlers

import android.content.Context
import androidx.credentials.CredentialManager
import androidx.credentials.CustomCredential
import androidx.credentials.GetCredentialRequest
import androidx.credentials.GetCredentialResponse
import androidx.credentials.exceptions.GetCredentialCancellationException
import com.example.sociallogin.config.SocialLoginConfig
import com.example.sociallogin.model.SocialLoginResult
import com.example.sociallogin.network.AuthApiService
import com.example.sociallogin.network.SocialAuthRequest
import com.example.sociallogin.storage.SecureTokenStorage
import com.google.android.libraries.identity.googleid.GetGoogleIdOption
import com.google.android.libraries.identity.googleid.GoogleIdTokenCredential
import com.google.android.libraries.identity.googleid.GoogleIdTokenParsingException
import java.security.SecureRandom
import java.util.Base64

class GoogleLoginHandler(
    private val apiService: AuthApiService,
    private val tokenStorage: SecureTokenStorage
) {
    /**
     * Initiates Google Sign-In using Credential Manager.
     * Returns an ID token which we send to our backend.
     * The backend verifies the ID token with Google and
     * exchanges it using the Client Secret (server-side only).
     */
    suspend fun login(context: Context): SocialLoginResult {
        return try {
            val credentialManager = CredentialManager.create(context)

            // Generate a nonce for replay protection
            val nonce = generateNonce()

            val googleIdOption = GetGoogleIdOption.Builder()
                .setFilterByAuthorizedAccounts(false)
                .setServerClientId(SocialLoginConfig.GOOGLE_SERVER_CLIENT_ID)
                .setNonce(nonce)
                .build()

            val request = GetCredentialRequest.Builder()
                .addCredentialOption(googleIdOption)
                .build()

            val result = credentialManager.getCredential(
                request = request,
                context = context
            )

            handleGoogleSignInResult(result)
        } catch (e: GetCredentialCancellationException) {
            SocialLoginResult.Cancelled
        } catch (e: Exception) {
            SocialLoginResult.Error("Google sign-in failed: ${e.message}", e)
        }
    }

    private suspend fun handleGoogleSignInResult(
        response: GetCredentialResponse
    ): SocialLoginResult {
        val credential = response.credential

        if (credential is CustomCredential &&
            credential.type == GoogleIdTokenCredential.TYPE_GOOGLE_ID_TOKEN_CREDENTIAL
        ) {
            return try {
                val googleIdTokenCredential =
                    GoogleIdTokenCredential.createFrom(credential.data)
                val idToken = googleIdTokenCredential.idToken

                exchangeTokenWithBackend(idToken)
            } catch (e: GoogleIdTokenParsingException) {
                SocialLoginResult.Error("Failed to parse Google ID token", e)
            }
        }

        return SocialLoginResult.Error("Unexpected credential type")
    }

    private suspend fun exchangeTokenWithBackend(idToken: String): SocialLoginResult {
        return try {
            // Send the Google ID token to our backend.
            // The backend verifies it with Google using the Client Secret
            // and creates/finds the user account.
            val response = apiService.authenticateWithSocial(
                SocialAuthRequest(
                    provider = "google",
                    idToken = idToken
                )
            )

            if (response.isSuccessful && response.body() != null) {
                val authResponse = response.body()!!
                tokenStorage.saveAccessToken("app", authResponse.accessToken)
                tokenStorage.saveRefreshToken("app", authResponse.refreshToken)

                SocialLoginResult.Success(
                    accessToken = authResponse.accessToken,
                    refreshToken = authResponse.refreshToken,
                    user = authResponse.user
                )
            } else {
                SocialLoginResult.Error(
                    "Backend authentication failed: ${response.code()}"
                )
            }
        } catch (e: Exception) {
            SocialLoginResult.Error("Network error: ${e.message}", e)
        }
    }

    private fun generateNonce(): String {
        val bytes = ByteArray(32)
        SecureRandom().nextBytes(bytes)
        return Base64.getUrlEncoder().withoutPadding().encodeToString(bytes)
    }

    fun logout() {
        tokenStorage.clearTokens("app")
    }
}


// --- Social Login Manager (Facade) ---

package com.example.sociallogin

import android.app.Activity
import android.content.Context
import android.content.Intent
import com.example.sociallogin.handlers.FacebookLoginHandler
import com.example.sociallogin.handlers.GoogleLoginHandler
import com.example.sociallogin.model.SocialLoginResult
import com.example.sociallogin.network.NetworkModule
import com.example.sociallogin.storage.SecureTokenStorage

class SocialLoginManager private constructor(
    context: Context
) {
    private val tokenStorage = SecureTokenStorage(context.applicationContext)
    private val apiService = NetworkModule.createApiService(tokenStorage)

    val facebookLogin = FacebookLoginHandler(apiService, tokenStorage)
    val googleLogin = GoogleLoginHandler(apiService, tokenStorage)

    val isLoggedIn: Boolean
        get() = tokenStorage.getAccessToken("app") != null

    suspend fun loginWithFacebook(activity: Activity): SocialLoginResult {
        return facebookLogin.login(activity)
    }

    suspend fun loginWithGoogle(context: Context): SocialLoginResult {
        return googleLogin.login(context)
    }

    fun handleActivityResult(requestCode: Int, resultCode: Int, data: Intent?) {
        facebookLogin.handleActivityResult(requestCode, resultCode, data)
    }

    fun logout() {
        facebookLogin.logout()
        googleLogin.logout()
        tokenStorage.clearAll()
    }

    companion object {
        @Volatile
        private var instance: SocialLoginManager? = null

        fun getInstance(context: Context): SocialLoginManager {
            return instance ?: synchronized(this) {
                instance ?: SocialLoginManager(context.applicationContext).also {
                    instance = it
                }
            }
        }
    }
}


