package com.example.sociallogin.ui

import android.app.Activity
import android.app.Application
import android.content.Context
import androidx.lifecycle.AndroidViewModel
import androidx.lifecycle.viewModelScope
import com.example.sociallogin.SocialLoginManager
import com.example.sociallogin.model.SocialLoginResult
import kotlinx.coroutines.flow.MutableStateFlow
import kotlinx.coroutines.flow.StateFlow
import kotlinx.coroutines.flow.asStateFlow
import kotlinx.coroutines.launch

data class LoginUiState(
    val isLoading: Boolean = false,
    val isLoggedIn: Boolean = false,
    val userName: String? = null,
    val errorMessage: String? = null
)

class LoginViewModel(application: Application) : AndroidViewModel(application) {

    private val loginManager = SocialLoginManager.getInstance(application)

    private val _uiState = MutableStateFlow(
        LoginUiState(isLoggedIn = loginManager.isLoggedIn)
    )
    val uiState: StateFlow<LoginUiState> = _uiState.asStateFlow()

    fun loginWithFacebook(activity: Activity) {
        viewModelScope.launch {
            _uiState.value = _uiState.value.copy(isLoading = true, errorMessage = null)

            when (val result = loginManager.loginWithFacebook(activity)) {
                is SocialLoginResult.Success -> {
                    _uiState.value = LoginUiState(
                        isLoggedIn = true,
                        userName = result.user.name
                    )
                }
                is SocialLoginResult.Error -> {
                    _uiState.value = _uiState.value.copy(
                        isLoading = false,
                        errorMessage = result.message
                    )
                }
                SocialLoginResult.Cancelled -> {
                    _uiState.value = _uiState.value.copy(isLoading = false)
                }
            }
        }
    }

    fun loginWithGoogle(context: Context) {
        viewModelScope.launch {
            _uiState.value = _uiState.value.copy(isLoading = true, errorMessage = null)

            when (val result = loginManager.loginWithGoogle(context)) {
                is SocialLoginResult.Success -> {
                    _uiState.value = LoginUiState(
                        isLoggedIn = true,
                        userName = result.user.name
                    )
                }
                is SocialLoginResult.Error -> {
                    _uiState.value = _uiState.value.copy(
                        isLoading = false,
                        errorMessage = result.message
                    )
                }
                SocialLoginResult.Cancelled -> {
                    _uiState.value = _uiState.value.copy(isLoading = false)
                }
            }
        }
    }

    fun logout() {
        loginManager.logout()
        _uiState.value = LoginUiState()
    }
}


